app.use(helmet());                                // sets secure HTTP headers
app.use(cors({ origin: process.env.ALLOWED_ORIGIN || false }));
app.use(express.json({ limit: '10kb' }));          // cap request bodies
app.use(rateLimit({ windowMs: 60_000, max: 100 })); // basic DoS protection
app.disable('x-powered-by');                       // don't leak framework
```

### 2. No global error handler
Any thrown error (sync or async) currently bubbles up and can crash the process or leak a stack trace to clients.

```js
// After all routes:
app.use((err, req, res, next) => {
  // Log full detail server-side, return sanitized message client-side
  req.log?.error({ err }, 'unhandled error');
  const status = err.status || 500;
  res.status(status).json({
    error: status === 500 ? 'Internal Server Error' : err.message,
  });
});

