app.use((req, res) => res.status(404).json({ error: 'Not Found' }));
```

### 3. No process-level safety nets
`listen()` has no error callback, and there are no handlers for `uncaughtException` / `unhandledRejection`.

```js
const server = app.listen(PORT, () => {...});

server.on('error', (err) => {
  console.error('Server failed to start:', err);
  process.exit(1);
});

process.on('unhandledRejection', (reason) => {
  console.error('Unhandled rejection:', reason);
});
process.on('uncaughtException', (err) => {
  console.error('Uncaught exception:', err);
  server.close(() => process.exit(1));
});

// Graceful shutdown
for (const sig of ['SIGTERM', 'SIGINT']) {
  process.on(sig, () => server.close(() => process.exit(0)));
}
```

### 4. No input validation
Current routes don't accept input, but any future route should validate before use. Use a schema validator (Zod, Joi, express-validator) rather than ad-hoc checks.

```js
const { z } = require('zod');

const userIdSchema = z.object({
  id: z.coerce.number().int().positive().max(1_000_000),
});

app.get('/users/:id', (req, res, next) => {
  const parsed = userIdSchema.safeParse(req.params);
