  res.status(404).json({ error: 'Not found' });
});

// Global error handler (must have 4 args)
app.use((err, req, res, next) => {
  console.error(err); // log to proper logger in production
  const status = err.status || 500;
  // Never leak internal error details in production
  res.status(status).json({
    error: process.env.NODE_ENV === 'production' ? 'Internal server error' : err.message,
  });
});

// Catch unhandled rejections and exceptions
process.on('unhandledRejection', (reason) => {
  console.error('Unhandled rejection:', reason);
});
process.on('uncaughtException', (err) => {
  console.error('Uncaught exception:', err);
  process.exit(1);
});
```

## 2. No Security Middleware

**Issue:** Responses lack basic security headers (CSP, HSTS, X-Frame-Options, etc.), and there is no rate limiting or CORS policy.

**Recommendation:**
```js
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const cors = require('cors');

app.use(helmet());
app.use(cors({ origin: process.env.ALLOWED_ORIGIN || 'https://example.com' }));
app.use(rateLimit({ windowMs: 60_000, max: 100 }));
app.disable('x-powered-by'); // helmet does this, but explicit is fine
```

## 3. No Body Parsing Limits

**Issue:** If you add POST/PUT routes, default `express.json()` has a 100kb limit, but it's worth setting explicitly to defend against payload-based DoS.

**Recommendation:**
```js
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));
```

## 4. No Input Validation on Routes

**Issue:** The `/users` route ignores any query/params today, but as soon as filtering (e.g. `/users?id=1`) is added, unvalidated input becomes a risk (injection, NoSQL injection, type confusion).

**Recommendation:** Use a schema validator such as `zod` or `joi`, and wrap async handlers to funnel errors to the error middleware.
```js
