process.on('uncaughtException',  (err)    => { console.error('uncaughtException', err); process.exit(1); });

const server = app.listen(PORT, () => { /* ... */ });
server.on('error', (err) => { console.error('listen error', err); process.exit(1); });
```

## 2. No input validation

Neither route validates request input today, but the moment you add query params (e.g., `/users?id=…`) or a body, you need validation. Use a schema validator like **zod**, **joi**, or **express-validator** and reject unknown fields.

```js
const { z } = require('zod');

const listUsersQuery = z.object({
  limit: z.coerce.number().int().min(1).max(100).default(20),
  offset: z.coerce.number().int().min(0).default(0),
}).strict();

app.get('/users', (req, res, next) => {
  const parsed = listUsersQuery.safeParse(req.query);
  if (!parsed.success) return res.status(400).json({ error: parsed.error.flatten() });
  // ... use parsed.data
});
```

Also: if you later add `app.use(express.json())`, cap the body size (`express.json({ limit: '10kb' })`) to mitigate DoS via huge payloads.

## 3. Security headers & hardening

Add `helmet` for sensible defaults (CSP, HSTS, X-Content-Type-Options, frame-ancestors, etc.) and disable the `X-Powered-By` header.

```js
const helmet = require('helmet');
app.disable('x-powered-by');
app.use(helmet());
```

## 4. Rate limiting & abuse protection

No rate limiting is in place — trivial to abuse. Add `express-rate-limit` (or equivalent) at least on public endpoints:

```js
const rateLimit = require('express-rate-limit');
app.use(rateLimit({ windowMs: 60_000, max: 100, standardHeaders: true, legacyHeaders: false }));
```

If deployed behind a proxy (nginx, ALB, Cloudflare), also set `app.set('trust proxy', 1)` so rate limiting uses the correct client IP.

## 5. CORS

Not configured. If browsers will call this API, allow-list specific origins rather than using `cors()` with defaults:

```js
const cors = require('cors');
app.use(cors({ origin: ['https://your-frontend.example.com'], methods: ['GET'] }));
```

## 6. PII leakage on `/users`

The endpoint returns email addresses with no authentication, authorization, pagination, or field whitelisting. For a real app:

- Require auth (e.g., JWT/session) before returning user data.
- Return only fields the caller is authorized to see (drop `email` for unauthenticated callers).
- Paginate (`limit`/`offset` or cursor) to prevent full-table scans.

## 7. Configuration & secrets

Port is hardcoded. Read from env so it can be configured per environment and so the app fails loudly if required config is missing:

```js
const PORT = Number(process.env.PORT) || 3000;
if (!Number.isInteger(PORT) || PORT <= 0) throw new Error('Invalid PORT');
```

Never log secrets, tokens, or full request bodies.

## 8. Graceful shutdown

Add SIGTERM/SIGINT handlers so in-flight requests drain cleanly (important behind load balancers and in containers):

```js
for (const sig of ['SIGINT', 'SIGTERM']) {
  process.on(sig, () => server.close(() => process.exit(0)));
}
```

## 9. Async route safety

Sync handlers today are fine, but once a route becomes `async`, unhandled rejections won't reach Express' error middleware unless you wrap them. Either use Express 5 (which handles this natively) or a wrapper:

```js
const asyncH = (fn) => (req, res, next) => Promise.resolve(fn(req, res, next)).catch(next);
app.get('/users', asyncH(async (req, res) => { /* ... */ }));
```

