  console.error({ msg: 'Unhandled error', err: err.message, stack: err.stack });
  const isProd = process.env.NODE_ENV === 'production';
  res.status(err.status || 500).json({
    error: isProd ? 'Internal server error' : err.message,
  });
});

process.on('unhandledRejection', (reason) => {
  console.error('Unhandled rejection:', reason);
});
process.on('uncaughtException', (err) => {
  console.error('Uncaught exception:', err);
  process.exit(1);
});

const server = app.listen(3000, () => { /* ... */ });
server.on('error', (err) => console.error('Listen error:', err));
```

## 2. No input validation / parsing safety

Neither endpoint takes input today, but there's no `express.json()` middleware configured. When you add POST/PUT routes, you should:

- Use `express.json({ limit: '100kb' })` — explicit limit prevents payload-based DoS.
- Validate all inputs with a schema library (`zod`, `joi`, or `express-validator`), never trust `req.body`, `req.query`, or `req.params` directly.
- Validate URL params (e.g. `/users/:id`) — coerce and bounds-check before DB lookups to prevent NoSQL/SQL injection and type-confusion bugs.

Example pattern:
```js
