app.use((err, req, res, next) => {
  console.error(err); // log server-side only
  const status = err.status || 500;
  res.status(status).json({
    error: status >= 500 ? 'Internal Server Error' : err.message,
  });
});

// Handle async crashes
process.on('unhandledRejection', (reason) => console.error('unhandledRejection', reason));
process.on('uncaughtException', (err) => { console.error('uncaughtException', err); process.exit(1); });
```

## 2. Missing Security Middleware

**Issue:** No `helmet`, CORS policy, rate limiting, or body-size limits.

**Recommendation:**
```js
const helmet = require('helmet');
const cors = require('cors');
const rateLimit = require('express-rate-limit');

app.use(helmet()); // sets secure HTTP headers (CSP, HSTS, X-Frame-Options, etc.)
app.use(cors({ origin: process.env.ALLOWED_ORIGIN || false })); // deny-by-default
app.use(express.json({ limit: '10kb' })); // cap JSON payloads
app.use(rateLimit({ windowMs: 60_000, max: 100 })); // basic DoS protection
app.disable('x-powered-by'); // hide framework fingerprint
```

