const { z } = require('zod');

const idSchema = z.coerce.number().int().positive().max(1_000_000);

app.get('/users/:id', (req, res, next) => {
  const result = idSchema.safeParse(req.params.id);
  if (!result.success) return res.status(400).json({ error: 'Invalid id' });
  // ... lookup by result.data
});
```
Always validate **type, range, length, and format** before using input in DB queries, filesystem paths, or shell commands.

## 4. Hard-Coded Port & No Graceful Shutdown

**Issue:** Port `3000` is hard-coded; `SIGTERM` kills in-flight requests.

**Recommendation:**
