app.use(helmet());
app.use(express.json({ limit: '10kb' }));
app.use(rateLimit({ windowMs: 60_000, max: 100 }));

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob',   email: 'bob@example.com'   },
  ]);
});

app.use((req, res) => res.status(404).json({ error: 'Not found' }));
app.use((err, req, res, next) => {
  console.error(err);
  res.status(err.status || 500).json({ error: 'Internal server error' });
});

if (require.main === module) {
  const server = app.listen(port, () => console.log(`Server running on port ${port}`));
  for (const sig of ['SIGTERM', 'SIGINT']) {
    process.on(sig, () => server.close(() => process.exit(0)));
  }
}

module.exports = app;
```

## Priority order
1. **Security middleware** (`helmet`, body size limit, rate limit, disable `x-powered-by`).
2. **Error + 404 handlers** so failures don't leak stack traces.
3. **Guard `listen()` behind `require.main`**.
4. **Validation framework** in place before adding parameterized routes.
5. **AuthN/AuthZ** before `/users` returns real data.

