const express = require('express');
const helmet = require('helmet');
const cors = require('cors');
const rateLimit = require('express-rate-limit');
const { query, validationResult } = require('express-validator');

const app = express();

// --- Security & hardening ---
app.disable('x-powered-by');
app.use(helmet());                                    // secure HTTP headers
app.use(cors({ origin: process.env.ALLOWED_ORIGIN })); // explicit allowlist
app.use(express.json({ limit: '10kb' }));              // cap body size (DoS defense)
app.use(rateLimit({ windowMs: 60_000, max: 100 }));    // basic rate limiting

// --- Async wrapper so thrown errors reach the error middleware ---
const asyncHandler = (fn) => (req, res, next) =>
  Promise.resolve(fn(req, res, next)).catch(next);

// --- Routes ---
